import { motion } from "framer-motion";

export default function HalftoneFocusCanvas() {
  return (() => <div style={{display:"grid",gridTemplateColumns:"repeat(11,1fr)",gap:10,alignContent:"center",height:"100%",minHeight:230,padding:20,background:"#fafafa",borderRadius:20}}>{Array.from({length:66},(_,i)=>{const x=i%11,y=Math.floor(i/11),d=Math.max(0,4-Math.hypot(x-7,y-3));return <motion.span key={i} whileHover={{scale:1.8,backgroundColor:"#53e8d4"}} style={{justifySelf:"center",width:3+d*2,height:3+d*2,borderRadius:99,background:i===40?"#53e8d4":"#111",opacity:.25+d*.15}}/>})}</div>)();
